-- Enrichment marathon batch: OpenRouteService, OpenSearch, OpenShot, OpenSign, openSIPS, OpenSlides, OpenSMTPD, OpenSSH SFTP server

-- ── OpenRouteService ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenRouteService (ORS) is a free, open-source geospatial routing and directions API built on OpenStreetMap data by HeiGIT, the Heidelberg Institute for Geoinformation Technology.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$Non-profit research institute (HeiGIT gGmbH, a spin-off of Heidelberg University's GIScience Research Group)$q$, company_size),
  headquarters = COALESCE($q$Heidelberg, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenRouteService Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenRouteService review covering routing and isochrone APIs, free tier limits, pricing, key features, and top alternatives like OSRM, GraphHopper and Mapbox.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenRouteService (ORS) is a free, open-source routing and geospatial analysis API built entirely on OpenStreetMap (OSM) data. It originated in 2008 as a research project of the GIScience Research Group, led by Professor Alexander Zipf, at Heidelberg University in Germany. The project matured into HeiGIT gGmbH (Heidelberg Institute for Geoinformation Technology), a non-profit research institute that now develops and operates the service alongside other OSM-based location tools. ORS provides a suite of endpoints including Directions (turn-by-turn routing for car, bike, foot, wheelchair, and heavy-goods-vehicle profiles), Isochrones (reachability/travel-time polygons), Matrix (many-to-many travel time and distance calculations), Geocoding (Pelias-based address search), POIs, and elevation and optimization services. It differentiates itself from commercial routing APIs like Google Maps Directions or Mapbox Directions by being fully open source, transparent about its OSM data lineage, and free to self-host, while still offering a managed cloud API for convenience. Its target audience spans academic researchers, GIS professionals, logistics and mobility startups, NGOs doing humanitarian mapping, and developers who want OSM-based routing without vendor lock-in. The hosted API is accessed via a free API key through a HeiGIT account, with a free tier covering roughly 2,500 requests per day and 40,000 per month across all endpoints, suitable for personal projects, research, and early-stage commercial development; higher-volume commercial and enterprise use requires a paid HeiGIT plan or self-hosting the open-source backend (openrouteservice-backend on GitHub) on a customer's own infrastructure, which removes rate limits entirely at the cost of running the OSM data pipeline. With over a decade of development and reportedly more than 150,000 users worldwide, ORS is considered one of the most established open-source, OSM-based routing engines, alongside OSRM and GraphHopper. Its main competitors are Google Maps Platform Directions API, Mapbox Directions API, HERE Routing, GraphHopper, and Open Source Routing Machine (OSRM) -- a separate, distinct routing engine project. ORS is licensed under GPLv3 for its backend, and its underlying data inherits the Open Database License of OpenStreetMap. Because it is grounded in academic geoinformatics research, ORS is frequently cited in scientific papers on accessibility analysis, humanitarian logistics, and urban mobility planning, giving it credibility in domains where data provenance and algorithmic transparency matter more than raw API polish.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bc74d5c2-961f-4a99-a34b-c92eee310096';

