-- ── OpenSearch ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenSearch is an Apache 2.0-licensed open-source search, analytics, observability, and vector database engine, originally forked from Elasticsearch and Kibana by AWS in 2021 and now governed by the OpenSearch Software Foundation under the Linux Foundation.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Open source foundation project (OpenSearch Software Foundation, part of the Linux Foundation, with premier members AWS, SAP and Uber)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA (Linux Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenSearch Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenSearch review covering search, analytics, observability and vector search features, self-hosted and AWS managed pricing, and alternatives to Elasticsearch.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenSearch is an open-source search, analytics, observability, and vector database platform originally created in 2021 by Amazon Web Services as a fork of Elasticsearch and Kibana, after Elastic NV relicensed those projects away from the open-source Apache 2.0 license to the Server Side Public License (SSPL). AWS forked the last Apache 2.0 versions of Elasticsearch and Kibana to create OpenSearch and OpenSearch Dashboards, preserving open-source access for the community and its own managed Amazon OpenSearch Service customers. In September 2024, governance of the project was transferred from AWS to the newly formed OpenSearch Software Foundation, organized as an open technical project within the Linux Foundation, with premier members AWS, SAP, and Uber, and general members including Aiven, Aryn, Atlassian, Canonical, DigitalOcean, Eliatra, Graylog, and NetApp Instaclustr. By 2025 the project had surpassed roughly one billion cumulative software downloads with contributions from thousands of developers and more than 200 project maintainers. Functionally, OpenSearch competes directly with Elasticsearch and Apache Solr as a distributed search and analytics engine: it powers full-text search, log analytics, security analytics, and infrastructure observability through OpenSearch Dashboards (its Kibana-equivalent visualization layer). A key differentiator versus Elastic's current licensing model is that OpenSearch bundles enterprise-grade features -- fine-grained security (LDAP, SAML, field- and document-level access control), alerting, anomaly detection, machine learning, and searchable snapshots -- for free under Apache 2.0, rather than gating them behind a paid tier. OpenSearch also has a mature k-NN plugin for vector search and embeddings, positioning it as a viable vector database for retrieval-augmented generation (RAG) and AI search applications, with active development of GPU acceleration (via NVIDIA cuVS) for large-scale vector workloads. There is no licensing cost to self-host OpenSearch; organizations that prefer a managed offering typically use Amazon OpenSearch Service or OpenSearch Serverless, which are billed by AWS on a usage basis (instance-hours, storage, and data transfer), or third-party managed OpenSearch offerings from vendors like Aiven, DigitalOcean, or Instaclustr. Target users range from individual developers self-hosting a small search cluster to large enterprises running petabyte-scale observability and security-analytics platforms. Its primary competitors are Elasticsearch, Apache Solr, Algolia, Meilisearch, and Typesense, with OpenSearch generally positioned as the most Elasticsearch-API-compatible, fully open-source, vendor-neutral option in the category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '897517f2-e813-44cf-9a91-5b3befd56d44';

