-- ── OpenSign ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenSign is an open-source electronic signature platform, founded in 2023, that offers a free self-hosted version and paid cloud plans as an alternative to DocuSign.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Early-stage startup (small team)$q$, company_size),
  headquarters = COALESCE($q$New York City, New York, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenSign Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenSign review covering the open-source e-signature platform's features, free and paid pricing plans, and alternatives to DocuSign and HelloSign.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenSign is an open-source electronic signature and digital document-signing platform founded in 2023 and headquartered in New York City. It positions itself explicitly as a free and open-source alternative to DocuSign, built on the Parse Platform backend, and is distributed both as a self-hosted open-source project (available on GitHub as OpenSignLabs/OpenSign) and as a hosted cloud service run by OpenSign Labs. The self-hosted, free version can be downloaded, deployed, and modified at no cost, and it supports unlimited document creation and signature requests, making it attractive to privacy-conscious organizations, developers, and cost-sensitive businesses that want full control over their signing infrastructure and data residency. The hosted cloud product offers a tiered pricing model: a Free plan for individuals with basic signing needs; a Professional plan at 9.99 US dollars per month adding advanced field validations, webhooks, Zapier integration, API access with a monthly allotment of API signatures, and custom email templates; a Teams plan at 19.99 US dollars per user per month that layers on a larger API signature allotment, team and organization management, template sharing, and bulk sending for up to 50 documents at once; and a custom-priced Enterprise plan adding a custom domain, white-labeling, an uptime SLA, single sign-on (SSO), and priority support. Core product features include multi-signer sequential and parallel signing workflows, one-time-password (OTP) identity verification, detailed audit trails for legal compliance, reusable document templates, embeddable signing widgets for integrating into other web apps, and support for common document formats including PDF, DOCX, JPG, and PNG. As an unfunded, bootstrapped startup rather than a venture-backed company, OpenSign competes primarily on cost and transparency against established e-signature incumbents such as DocuSign, Dropbox Sign (formerly HelloSign), PandaDoc, SignNow, and Adobe Acrobat Sign, appealing especially to startups, small and medium businesses, and open-source-first organizations that find those incumbents' pricing or vendor lock-in unattractive. Because the underlying code is open source, OpenSign also serves developers who want to embed e-signature functionality directly into their own products via API rather than relying on a third-party SaaS subscription indefinitely.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8b92e33a-9ce9-4f11-bf8a-c6758fc2237c';

