-- ── OpenSlides ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenSlides is an open-source assembly and meeting management platform for agendas, motions, and electronic voting, developed by Intevation GmbH in Osnabrück, Germany.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Small-to-midsize IT services company (Intevation GmbH, founded 1999)$q$, company_size),
  headquarters = COALESCE($q$Osnabrück, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$OpenSlides Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenSlides review covering the open-source assembly and e-voting platform's features, free self-hosted option, SaaS pricing, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenSlides is an open-source digital assembly and meeting management system used to run agendas, motions, elections, and electronic voting for parliamentary-style organizations, associations, and committees. Its roots trace to 2005, when Emanuel Schütze built an early PHP prototype for the federal meetings of a German Protestant student association; at the end of 2010, Schütze, Oskar Hahn, and Norman Jäckel began a full rewrite in Python and Django, releasing OpenSlides version 1.0 on September 12, 2011. The project is developed and professionally operated by Intevation GmbH, an independent IT services company based in Osnabrück, Germany, founded in 1999 with a long-standing commitment to free and open-source software. OpenSlides is distributed under the MIT license as free/libre open-source software (FLOSS), meaning organizations can self-host it at no licensing cost, and an electronic voting module was added to the platform in 2019, extending it from presentation and agenda management into full legally-relevant electronic elections and motions voting. Beyond the free self-hosted option, Intevation offers OpenSlides as a hosted SaaS product with usage-based, per-account pricing across three tiers: Online Voting at 2 euros per account for a minimum 14-day event, starting at 50 accounts, covering live and unlimited online voting and elections; Conference Management at 4 euros per account for a minimum one-month engagement, covering the full feature range for one-time meetings including agenda, motions, and speaking lists; and Committee Management at 36 euros per account for a minimum 12-month term with fixed account tiers of 100, 250, 500, or 1000, designed for organizations running recurring, unlimited meetings and adding capabilities like single sign-on and integrated livestreaming. Core features across the platform include agenda and speaking-list management, a full motions workflow (submission, amendment, discussion, voting), candidate lists and election management, live projector output for displaying agendas and results during meetings, autopilot presentation mode, custom branding, and data export. OpenSlides primarily serves parliaments, political parties, non-profit associations, unions, cooperatives, and any membership organization that must run formal, auditable votes and motions according to procedural rules, positioning it against tools like Loomio, Decidim, and dedicated online-voting vendors such as Election Buddy and Simply Voting, as well as general conference/event platforms for organizations that only need the meeting-management side.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9dee94a4-8e82-47af-beeb-930afb5a54a0';

