-- ── OpenSMTPD ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenSMTPD is a free, open-source SMTP mail server daemon developed as part of the OpenBSD project, focused on security, simplicity, and easy configuration.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Open source project (OpenBSD)$q$, company_size),
  headquarters = COALESCE($q$Open source project (OpenBSD)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenSMTPD Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenSMTPD review covering the free, open-source OpenBSD SMTP server's features, security design, pricing, and alternatives like Postfix and Exim.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenSMTPD, also referred to as the OpenBSD SMTP Server, is a free and open-source Unix daemon that implements the Simple Mail Transfer Protocol (SMTP) to deliver email locally or relay it to other mail servers. It has been in development within the OpenBSD project since late 2008 and was first publicly released as version 5.3 on March 17, 2013. It is primarily developed by Gilles Chehade, Eric Faurot, and Charles Longeau as part of the broader OpenBSD operating system project, which is well known for prioritizing security and code auditability across all its components. OpenSMTPD was created specifically to address recurring problems the developers saw in existing SMTP daemons: difficult and error-prone configuration syntax, complex codebases that were hard to security-audit, and licensing terms the OpenBSD project considered unsuitable. Its design goals center on security, reliability, ease of configuration, and support for the most common real-world mail-server use cases, deliberately implementing a smaller feature surface than daemons like Postfix or Exim, prioritizing correctness and auditability over exhaustive configurability for niche scenarios. Security hardening techniques used internally include strict validity checking on all network input, bounded-buffer string operations (via strlcpy), and privilege separation, where different processes run with minimal privileges to contain the impact of any potential security vulnerability. The source code is released under the permissive ISC license, and like OpenSSH, OpenSMTPD has an official portable version maintained as a separate child project (initiated by Charles Longeau) that adds cross-platform support for NetBSD, FreeBSD, DragonFly BSD, and numerous Linux distributions, in addition to its native home on OpenBSD. As a component of the OpenBSD project rather than a commercial company, OpenSMTPD has no company size, headquarters, funding, or traditional pricing in the conventional sense; it is entirely free to download, deploy, and modify, and its typical use cases include local mail delivery, relaying, authenticated mail submission, and receiving mail for virtual domains on servers of any scale. Its direct competitors in the SMTP server daemon category are Postfix, Exim, Sendmail, and qmail, with OpenSMTPD generally positioned as the smallest, most security-focused, and easiest to configure of the group, at the cost of supporting fewer advanced or niche mail-routing features than the more mature and feature-rich Postfix or Exim.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '99730711-228d-48f9-acb0-4108e2522d7d';

