-- ── OpenSSH SFTP server ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenSSH SFTP server (sftp-server) is the free, open-source SFTP subsystem bundled with OpenSSH, providing secure file transfer over SSH as part of the OpenBSD project.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$Open source project (OpenBSD)$q$, company_size),
  headquarters = COALESCE($q$Open source project (OpenBSD)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenSSH SFTP Server Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenSSH SFTP server review covering sftp-server's history, features, free open-source pricing, and alternatives for secure file transfer over SSH.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenSSH SFTP server, commonly known by its binary name sftp-server, is the server-side subsystem that implements the SFTP (SSH File Transfer Protocol) within the OpenSSH suite. It provides secure, encrypted file transfer capability over an existing SSH connection and is invoked by the sshd daemon via the Subsystem configuration directive rather than being run directly by users. Support for the server side of SFTP was written by developer Markus Friedl and first released with OpenSSH 2.3.0 in November 2000, with sftp-server first appearing in OpenBSD 2.8. OpenSSH itself is developed as part of the OpenBSD operating system project, and traces its lineage to the original free ssh 1.2.12 release by Tatu Ylönen, the last version of that codebase free enough for the OpenBSD team to build upon; all patented or restrictively licensed components were subsequently removed or replaced with external libraries such as LibreSSL. Functionally, sftp-server works together with the sftp client command-line tool to give users and administrators a secure alternative to legacy, unencrypted FTP, transferring files, directories, and permissions over an authenticated, encrypted SSH channel. Key operational features include support for chrooted (jailed) SFTP-only user accounts, a read-only mode for restricting write access, configurable logging of file operations, and request filtering to restrict which SFTP protocol operations a given user or connection is permitted to perform, making it a common building block for secure file-transfer-only accounts on shared or multi-tenant servers. As a bundled component of OpenSSH, sftp-server has no independent company, funding, or headquarters; it is maintained by the OpenBSD project's core developers under a permissive BSD-style license, and is distributed and pre-installed with virtually every Linux distribution, BSD variant, and macOS as part of the standard OpenSSH package, making it arguably the single most widely deployed SFTP server implementation in the world by installation count, even though it is rarely marketed or discussed as a standalone product. Because it ships for free with the SSH daemon nearly every server already runs, its primary competitors are less other SFTP daemons and more alternative secure file transfer approaches: dedicated FTPS/SFTP daemons like ProFTPD, Pure-FTPd, or vsftpd (which primarily target FTP/FTPS rather than SFTP), and commercial managed file transfer (MFT) platforms such as GoAnywhere MFT or Globalscape, which add web UIs, workflow automation, and compliance reporting on top of core SFTP functionality that OpenSSH's sftp-server already provides for free at the protocol level.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4e5f6c77-3f3a-46b6-8db5-4bd0f9c1c6a9';

